  ('PRD0671','Анализ косметики',5634,'NIOD Superoxide Dismutase Saccharide Mist','NIOD Superoxide Dismutase Saccharide Mist','NIOD','Мист','Уход за кожей / Тонизирование / Мист','Лицо','Super oxide dismutase (SOD) - играет важную роль в защите клеток, находящихся в контакте с кислородом, Отличный антиоксидант, желанный компонент в антиэйдж косметике. Препятствует распаду коллагена и процессу гликации. Вводится в 0,02-0,09% концентрации.','Супероксиддисмутаза (SOD) — эффективный антиоксидант, востребованный в антивозрастной косметике. Защищает клетки, препятствует распаду коллагена и процессу гликации. Рекомендуемая концентрация — 0,02–0,09%.',false,NULL,NULL,NULL,5500,0,0,0,NULL,NULL,0,0,0,0,false,false,NULL,'Высокая',15,'B0231'),
  ('PRD0672','Анализ косметики',5650,'Лёгкая крем-сыворотка с комплексом витаминов и антиоксидантов Geltek VitaMatrix','Лёгкая крем-сыворотка с комплексом витаминов и антиоксидантов Geltek VitaMatrix','Гельтек','Сыворотка','Уход за кожей / Сыворотки и концентраты / Сыворотка','Лицо','базовая антиоксидантная сыворотка, защитит от окислительного стресса, увлажнит.','Базовая антиоксидантная сыворотка; защищает от окислительного стресса и увлажняет.',false,NULL,NULL,NULL,NULL,0,0,0,NULL,NULL,0,0,0,0,false,false,NULL,NULL,27,'B0377'),
  ('PRD0673','Анализ косметики',5678,'Joelle Ciocco Oxyclear Serum Антиоксидантная сыворотка для лица','Joelle Ciocco Oxyclear Serum Антиоксидантная сыворотка для лица','Joelle Ciocco','Сыворотка','Уход за кожей / Сыворотки и концентраты / Сыворотка','Лицо','дорогая антиокидантная сыворотка с потенциальными аллергенами, спиртом и не самой лучшей антиоксидантной защитой.','Антиоксидантная сыворотка премиального сегмента; содержит спирт и потенциальные аллергены, антиоксидантная защита умеренная.',false,NULL,NULL,NULL,16000,0,0,0,NULL,NULL,0,0,0,0,false,false,NULL,'Высокая',20,'B0174'),
  ('PRD0674','Анализ косметики',5699,'Антиоксидантная сыворотка Timeless Skin Care 20% Vitamin C + E Ferulic Acid Serum','Антиоксидантная сыворотка Timeless Skin Care 20% Vitamin C + E Ferulic Acid Serum','Timeless Skin Care','Сыворотка','Уход за кожей / Сыворотки и концентраты / Сыворотка','Лицо','Шикарная сыворотка с кислой формой витамина С, которая прослужит долго, благодаря вакуумной упаковке и антиоксидантам в составе, которые усилят стабильность кислой формы витамина С. Утром ее использовать можно, но при низком УФ-индексе 0-2, и под SPF защиту. При гиперпигментации лучше использовать вечером, ведь кислая форма витамина С может усилить пигмент.','Качественная сыворотка с кислой формой витамина С. Вакуумная упаковка и антиоксиданты в составе повышают стабильность. Утром применяется при низком УФ-индексе (0–2) под SPF-защитой; при гиперпигментации предпочтительно вечернее применение, так как кислая форма витамина С может усиливать пигментацию.',true,NULL,NULL,NULL,4000,0,0,0,NULL,NULL,0,0,0,0,false,false,NULL,'Высокая',11,'B0342'),
