  ('PRD0746','Анализ косметики',8281,'Балансирующий тоник на основе хауттюйнии Anua Heartleaf 77% Soothing Toner 250 мл','Балансирующий тоник на основе хауттюйнии Anua Heartleaf 77% Soothing Toner 250 мл','Uriage','Тонер','Уход за кожей / Тонизирование / Тонер','Лицо',NULL,NULL,true,NULL,NULL,NULL,2500,2,0,0,NULL,NULL,0,0,0,0,false,false,NULL,'Средняя',21,'B0350'),
  ('PRD0747','Анализ косметики',8303,'Onmacabim PMT Peeling Whitening пилинг отбеливающий 50 мл','Onmacabim PMT Peeling Whitening пилинг отбеливающий 50 мл','Timeless','Пилинг','Уход за кожей / Эксфолиация / Пилинг','Лицо',NULL,NULL,false,NULL,NULL,NULL,13000,0,0,0,NULL,NULL,0,0,0,0,false,false,NULL,'Высокая',8,'B0341'),
  ('PRD0748','Анализ косметики',8312,'Пирувиновый МультиПептидный Пилинг 55% рН 1.5±0.3','Пирувиновый МультиПептидный Пилинг 55% рН 1.5±0.3','Mixsoon','Пилинг','Уход за кожей / Эксфолиация / Пилинг','Лицо','Поэтому ПВК применяется в коррекции следующих эстетических проблем: себорейного дерматита, розацеа, гиперпигментации, фотостарения, атонии дермы, темных кругов под глазами.','Компонент применяется для коррекции себорейного дерматита, розацеа, гиперпигментации, фотостарения, атонии дермы и тёмных кругов под глазами.',false,NULL,NULL,NULL,NULL,0,0,0,NULL,NULL,0,0,0,0,false,false,NULL,NULL,15,'B0226'),
  ('PRD0749','Анализ косметики',8328,'Toun28 Propolis+Vitamin C, B3, B5, B6 Serum 30ml','Toun28 Propolis+Vitamin C, B3, B5, B6 Serum 30ml','UIQ','Сыворотка','Уход за кожей / Сыворотки и концентраты / Сыворотка','Лицо',NULL,NULL,false,NULL,NULL,NULL,3000,0,0,0,NULL,NULL,0,0,0,0,false,false,NULL,'Средняя',20,'B0348'),
  ('PRD0750','Анализ косметики',8349,'Активирующая бустер-эссенция By Wishtrend Energy Boosting Essence','Активирующая бустер-эссенция By Wishtrend Energy Boosting Essence','I''m from','Эссенция','Уход за кожей / Сыворотки и концентраты / Эссенция','Лицо',NULL,NULL,false,NULL,NULL,NULL,2400,0,0,0,NULL,NULL,0,0,0,0,false,false,NULL,'Средняя',19,'B0160'),
  ('PRD0751','Анализ косметики',8369,'Miracle CO2 pack Bubble gel (step I)','Miracle CO2 pack Bubble gel (step I)','Miracle','Гель','Уход за кожей / Увлажнение и питание / Гель','Лицо',NULL,NULL,false,NULL,NULL,NULL,NULL,0,0,0,NULL,NULL,0,0,0,0,false,false,NULL,NULL,9,'B0223'),
  ('PRD0752','Анализ косметики',8379,'Винный пилинг увлажняющий 10% Wine Peel Moisturizing Кислотный сдвиг (pH): 2.5','Винный пилинг увлажняющий 10% Wine Peel Moisturizing Кислотный сдвиг (pH): 2.5','BIDALLI','Пилинг','Уход за кожей / Эксфолиация / Пилинг','Лицо','Винная кислота - это сильный антиоксидант и биостимулятор. Находясь в составе какого-либо косметического средства, оказывает отшелушивающий и увлажняющий эффект.','Винная кислота — антиоксидант и биостимулятор; оказывает отшелушивающее и увлажняющее действие.',false,NULL,NULL,NULL,NULL,0,0,0,NULL,NULL,0,0,0,0,false,false,NULL,NULL,3,'B0044'),
  ('PRD0753','Анализ косметики',8383,'Активная пилинг-сыворотка с молочной кислотой The Ordinary Lactic Acid 10% + HA','Активная пилинг-сыворотка с молочной кислотой The Ordinary Lactic Acid 10% + HA','A''Pieu','Сыворотка','Уход за кожей / Сыворотки и концентраты / Сыворотка','Лицо','Молочная кислота связывает и удерживает влагу, создавая вокруг себя своего рода водную оболочку. Причем влага не просто собирается, но еще и правильно перераспределяется по направлению к глубоким, живым слоям кожи, что позволяет создать эффект сбалансированного увлажнения в эпидермисе','Молочная кислота связывает и удерживает влагу, перераспределяя её к глубоким слоям кожи и обеспечивая сбалансированное увлажнение эпидермиса.',false,NULL,NULL,NULL,1900,0,0,0,NULL,NULL,0,0,0,0,false,false,NULL,'Средняя',15,'B0006'),
  ('PRD0754','Анализ косметики',8399,'Onmacabin CLA пилинг с интенсивным кератолитическим действием','Onmacabin CLA пилинг с интенсивным кератолитическим действием','The Act','Пилинг','Уход за кожей / Эксфолиация / Пилинг','Лицо','Антиоксидантное, отбеливающее и антибактериальное действие при большой концентрации в составе. Но самостоятельно очень редко используется, чаще добавляется в состав в очень маленькой концентрации для осуществления хелатирующей (регулятор pH) функции','В высокой концентрации обладает антиоксидантным, осветляющим и антибактериальным действием. Чаще вводится в малой концентрации для хелатирующей функции и регуляции pH.',false,NULL,NULL,NULL,NULL,0,0,0,NULL,NULL,0,0,0,0,false,false,NULL,NULL,9,'B0333'),
  ('PRD0755','Анализ косметики',8409,'Веганский пилинг-тоник с 7% гликолевой кислоты The Ordinary Glycolic Acid 7% Exfoliating Toner','Веганский пилинг-тоник с 7% гликолевой кислоты The Ordinary Glycolic Acid 7% Exfoliating Toner','R+CO','Тонер','Уход за кожей / Тонизирование / Тонер','Лицо','Гликолевая кислота Увлажняет, отшелушивает, уменьшает пигментацию, сглаживает морщины. Сочетается со всеми кислотами. При показателе рН выше 3,5 увлажняет и совсем чуть чуть отшелушивает. Выраженные отшелушивающие свойства проявляются при ниже рН 3,5.','Гликолевая кислота увлажняет, отшелушивает, уменьшает пигментацию и сглаживает морщины; сочетается с другими кислотами. При pH выше 3,5 преобладает увлажняющее действие, выраженное отшелушивание проявляется при pH ниже 3,5.',false,NULL,NULL,NULL,2500,0,0,0,NULL,NULL,0,0,0,0,false,false,NULL,'Средняя',42,'B0275'),
  ('PRD0756','Анализ косметики',8452,'Всесезонный пилинг с 25% миндальной кислоты ICON SKIN 25 % Mandelic Smart Peel System','Всесезонный пилинг с 25% миндальной кислоты ICON SKIN 25 % Mandelic Smart Peel System','BENVOLEO','Пилинг','Уход за кожей / Эксфолиация / Пилинг','Лицо','В пилингах обязательно должны быть растворители кислот, иначе липофильные кислоты не смогут проникнуть в кожу. Здесь все прекрасно, кислота растворена в гликоле.','Пилинги должны содержать растворители кислот для проникновения липофильных кислот в кожу. В данном составе кислота растворена в гликоле.',true,NULL,NULL,NULL,NULL,0,0,0,NULL,NULL,0,0,0,0,false,false,NULL,NULL,22,'B0043'),
  ('PRD0757','Анализ косметики',8475,'Себорегулирующий гель Biretix Duo Purifying Exfoliant Gel/ Anti-Blemish Gel Cantabria Labs','Себорегулирующий гель Biretix Duo Purifying Exfoliant Gel/ Anti-Blemish Gel Cantabria Labs','DIKSON','Гель','Уход за кожей / Увлажнение и питание / Гель','Лицо','содержатся и кислоты, и ретиноиды. Само по себе сочетание может быть прекрасным и содержание компонентов в каждом средстве выверено, потому компоненты между собой дружат. Но если выстроить схему из линейки этого бренда или из подобных средств, в которых сочетаются кислоты и ретиноиды, (запоминайте) такой уход будет повреждать кожу, потому стоит сконцентрироваться на эффективных дозировках компонентов для коррекции эстетического несовершенства, а последующий уход пусть восстанавливает.','Содержит кислоты и ретиноиды в выверенных дозировках, совместимых в рамках одного средства. При построении ухода не рекомендуется сочетать несколько средств с кислотами и ретиноидами, чтобы избежать повреждения кожи; последующий уход должен быть восстанавливающим.',false,NULL,NULL,NULL,2500,0,0,0,NULL,NULL,0,0,0,0,false,false,NULL,'Средняя',33,'B0100'),
  ('PRD0758','Анализ косметики',8509,'ARAVIA PROFESSIONAL Гель очищающий с фруктовыми кислотами AHA - Fruit Gel, 250 мл','ARAVIA PROFESSIONAL Гель очищающий с фруктовыми кислотами AHA - Fruit Gel, 250 мл','EPICA','Гель','Уход за кожей / Увлажнение и питание / Гель','Тело','Видим жесткие ПАВ вместе с мягкими - уже предвидим глубокое очищение, при котором ПАВ растворяют межклеточные липиды. С другой стороны кислоты глубже проникают в кожу и «добивают» ее, растворяя жир и способствуя отшелушиванию кожи. Считается безопасным для кожи использовать очищение с кислотами 1 раз в 7-10 дней','Сочетание жёстких и мягких ПАВ обеспечивает глубокое очищение, при котором растворяются межклеточные липиды, а кислоты способствуют отшелушиванию. Очищение с кислотами рекомендуется применять 1 раз в 7–10 дней.',false,NULL,NULL,NULL,700,0,0,0,NULL,NULL,0,0,0,0,false,false,NULL,'Бюджетная',12,'B0118'),
  ('PRD0759','Анализ косметики',8522,'Мягкий тоник-эксфолиант с миндальной кислотой By Wishtrend Mandelic Acid 5% Prep Water','Мягкий тоник-эксфолиант с миндальной кислотой By Wishtrend Mandelic Acid 5% Prep Water','AVEDA','Тоник','Уход за кожей / Тонизирование / Тоник','Лицо','миндальная кислота липофильна, потому ей обязательно необходим растворитель, и он здесь есть в виде butylene glycol. Миндальные кислоты без растворителя сильно теряют свою эффективность и окажут лишь легкое антибактериальное действие обилие увлажняющих и снимающих раздражение компонентов делают средство универсальным, а наличие растворителя для миндальной кислоты делает средство еще и эффективным от воспалений и закупорки. При комедонах лучше использовать 10% миндальную кислоту.','Миндальная кислота липофильна и требует растворителя, роль которого выполняет butylene glycol. Без растворителя её эффективность снижается. Обилие увлажняющих и успокаивающих компонентов делает средство универсальным и эффективным против воспалений и закупорки пор. При комедонах предпочтительна 10% миндальная кислота.',false,NULL,NULL,NULL,2300,0,0,0,NULL,NULL,0,0,0,0,false,false,NULL,'Средняя',20,'B0022'),
  ('PRD0760','Анализ косметики',8543,'Невесомый солнцезащитный гель для лица Allies of Skin The One SPF 50 Invisible Sunscreen Gel','Невесомый солнцезащитный гель для лица Allies of Skin The One SPF 50 Invisible Sunscreen Gel','ALMA K.','Гель','Уход за кожей / Увлажнение и питание / Гель','Лицо','просто ужасный Пока фильтры нового поколения не прошли на территории США все проверки и клинические испытания, лучше покупать кремы производства других стран, ведь даже покупая дорогой или даже профессиональный косметологический крем, можно столкнуться с ужасным составом','Состав низкого качества. Поскольку УФ-фильтры нового поколения пока не прошли все проверки в США, предпочтительны кремы производства других стран.',false,NULL,NULL,NULL,5500,0,0,0,NULL,NULL,0,0,0,0,false,false,NULL,'Высокая',21,'B0013'),
  ('PRD0761','Анализ косметики',8565,'Тонизирующий солнцезащитный крем Derma Factory Inorganic Tone-Up Sun Cream SPF 50+ PA++++ 50 мл','Тонизирующий солнцезащитный крем Derma Factory Inorganic Tone-Up Sun Cream SPF 50+ PA++++ 50 мл','Rene Furterer','Крем','Уход за кожей / Увлажнение и питание / Крем','Лицо',NULL,NULL,false,NULL,NULL,NULL,1400,0,0,0,NULL,NULL,0,0,0,0,false,false,NULL,'Средняя',30,'B0285'),
  ('PRD0762','Анализ косметики',8596,'Garnier Ambre Solaire Эксперт-защита Солнцезащитный сухой спрей SPF 50+Garnier Ambre Solaire Эксперт-защита Солнцезащитный сухой спрей SPF 50+','Garnier Ambre Solaire Эксперт-защита Солнцезащитный сухой спрей SPF 50+Garnier Ambre Solaire Эксперт-защита Солнцезащитный сухой спрей SPF 50+','ARAVIA','Спрей','Уход за кожей / Увлажнение и питание / Спрей','Лицо','Добавлю, что найти идеальный состав спрея мало возможно, если вообще такой есть. СПФ обновлять важно, удобнее всего его обновлять стиком или спреем. Спрей важно вообще не вдыхать! И выбираем спрей (желательно) не более, чем с 1 фильтром старого поколения. Не забываем, спрей мы наносим поверх ухода, спф и макияжа, потому навредить коже будет сложно.','Идеального состава SPF-спрея практически не существует. Обновление SPF удобно выполнять стиком или спреем. Спрей не следует вдыхать; предпочтителен состав не более чем с одним УФ-фильтром предыдущего поколения. Поскольку спрей наносится поверх ухода, SPF и макияжа, риск негативного воздействия на кожу минимален.',false,NULL,NULL,NULL,1100,0,0,0,NULL,NULL,0,0,0,0,false,false,NULL,'Средняя',40,'B0015'),
  ('PRD0763','Анализ косметики',8637,'LA ROCHE-POSAY Anthelios Солнцезащитный крем-гель для жирной, проблемной, склонной к акне, кожи лица, с салициловой кислотой, ниацинамидом и цинком, SPF 50+, 50 мл','LA ROCHE-POSAY Anthelios Солнцезащитный крем-гель для жирной, проблемной, склонной к акне, кожи лица, с салициловой кислотой, ниацинамидом и цинком, SPF 50+, 50 мл','Lebel','Крем-гель','Уход за кожей / Увлажнение и питание / Крем-гель','Лицо',NULL,NULL,false,NULL,NULL,NULL,1700,0,0,0,NULL,NULL,0,0,0,0,false,false,NULL,'Средняя',38,'B0203'),
  ('PRD0764','Анализ косметики',8676,'La roche posay Солнцезащитный невидимый флюид для лица SPF50+ / PPD 42, 50 мл (La Roche-Posay, Anthelios)','La roche posay Солнцезащитный невидимый флюид для лица SPF50+ / PPD 42, 50 мл (La Roche-Posay, Anthelios)','Ринфолтил','Флюид','Уход за кожей / Сыворотки и концентраты / Флюид','Лицо','Смесь фильтров старого и нового поколения, и фильтров нового поколения больше. С одной стороны крем можно использовать здоровой коже, если других альтернатив нет, а с другой стороны нельзя чувствительной, сухой коже, при розацеа и обезвоженности, в том числе из-за спирта.','Содержит смесь УФ-фильтров предыдущего и нового поколения с преобладанием новых. Подходит здоровой коже при отсутствии альтернатив, но не рекомендуется чувствительной, сухой, обезвоженной коже и при розацеа, в том числе из-за наличия спирта.',false,NULL,NULL,NULL,2500,0,0,0,NULL,NULL,0,0,0,0,false,false,NULL,'Средняя',38,'B0386'),
  ('PRD0765','Анализ косметики',8715,'Солнцезащитный крем с центеллой PURITO Centella Green Level Unscented Sun SPF50+PA+++','Солнцезащитный крем с центеллой PURITO Centella Green Level Unscented Sun SPF50+PA+++','Ecolatier','Крем','Уход за кожей / Увлажнение и питание / Крем','Лицо','Исследования показали только спф 19','По результатам исследований фактический SPF составил около 19.',false,NULL,NULL,NULL,1900,0,0,0,NULL,NULL,0,0,0,0,false,false,NULL,'Средняя',32,'B0121'),
